args.command:
python3 -c "
lines = open('JOURNAL.md').readlines()
entries = []
current = None
for i, line in enumerate(lines):
    if line.startswith('## '):
        if current is not None:
            entries.append(current)
        current = {'title': line.strip(), 'line': i+1, 'body_lines': []}
    elif current is not None:
        current['body_lines'].append(line)

if current:
    entries.append(current)

# Show last 10 (which are the first 10 since newest is first)
for e in entries[:10]:
    # Get first non-empty body line as summary
    summary = ''
    for bl in e['body_lines']:
        s = bl.strip()
        if s and not s.startswith('**'):
            summary = s[:120]
            if len(bl.strip()) > 120:
                summary += '...'
            break
    print(f\"{e['title']}\")
    if summary:
        print(f\"  → {summary}\")
    print()
"

